mapper.select:
select d.id , d.name , d.category_id , d.price , d.image , d.description
     , d.status , d.create_time , d.update_time , c.name as categoryName
from dish d left join category c on c.id = d.category_id


            d.category_id = #{categoryId}


            and d.name like concat('%',#{name},'%')


            and d.status = #{status}


limit #{start}, #{pageSize};
